'use client';

import { useEffect, useState } from 'react';
import { useParams } from 'next/navigation';
import Link from 'next/link';

const DISCLAIMER =
  'This output is generated by AI agents for research purposes only. ' +
  'It does not constitute medical advice, diagnosis, or treatment recommendation. ' +
  'All findings must be validated by qualified researchers before any use.';

const REPORT_LOAD_TIMEOUT_MS = 10000;

type ConfidenceLevel = 'high' | 'medium' | 'low';

// ─── Design tokens ────────────────────────────────────────────────────────────
const SECTION_CARD   = 'rounded-2xl border border-slate-800 bg-slate-900/60 p-6 md:p-8';
const INNER_CARD     = 'rounded-xl border border-slate-800 bg-slate-950/60 p-5';
const SECTION_TITLE  = 'text-base font-semibold tracking-tight text-slate-100';
const SECTION_LABEL  = 'text-[10px] font-semibold uppercase tracking-[0.16em] text-slate-500';
const BODY_TEXT      = 'text-sm leading-relaxed text-slate-300';
const MUTED_TEXT     = 'text-xs text-slate-500';

// ─── Badge helpers ─────────────────────────────────────────────────────────────
// Unified level badge: high = green, medium = amber, low = red
const levelBadge = (value?: string) => {
  if (value === 'high')   return 'bg-emerald-950/50 text-emerald-300 border-emerald-700';
  if (value === 'medium') return 'bg-amber-950/50   text-amber-300  border-amber-600';
  if (value === 'low')    return 'bg-rose-950/50    text-rose-300   border-rose-700';
  return 'bg-slate-800 text-slate-400 border-slate-700';
};

const confidenceBadge = (value: ConfidenceLevel) =>
  levelBadge(value) + ' ring-1 ring-inset ring-white/5';

// Literature paper badges all use the same semantic scale
const evidenceBadge  = levelBadge;
const maturityBadge  = levelBadge;
const riskBadge      = levelBadge;

// Confidence sort order
const CONF_ORDER: Record<string, number> = { high: 0, medium: 1, low: 2 };
const byConfidence = (a: any, b: any) =>
  (CONF_ORDER[a.confidence] ?? 3) - (CONF_ORDER[b.confidence] ?? 3);

// ─── Score ring ───────────────────────────────────────────────────────────────
function ScoreRing({ score }: { score: number }) {
  const clamped = Math.min(Math.max(score, 0), 100);
  const radius = 18;
  const circ   = 2 * Math.PI * radius;
  const offset = circ - (clamped / 100) * circ;
  const color  = clamped >= 70 ? '#34d399' : clamped >= 45 ? '#fbbf24' : '#f87171';
  return (
    <div className="relative flex items-center justify-center w-14 h-14 flex-shrink-0">
      <svg width="56" height="56" viewBox="0 0 56 56" className="rotate-[-90deg]" aria-hidden="true">
        <circle cx="28" cy="28" r={radius} fill="none" stroke="#1e293b" strokeWidth="4" />
        <circle
          cx="28" cy="28" r={radius} fill="none"
          stroke={color} strokeWidth="4"
          strokeDasharray={circ} strokeDashoffset={offset}
          strokeLinecap="round"
          style={{ transition: 'stroke-dashoffset 0.6s ease' }}
        />
      </svg>
      <span className="absolute text-xs font-semibold text-slate-200">{score}</span>
    </div>
  );
}

// ─── Sub-score pills ──────────────────────────────────────────────────────────
function SubScorePills({ c }: { c: any }) {
  const items = [
    { label: 'Literature', value: c.literature_score },
    { label: 'Mechanism',  value: c.mechanism_score  },
    { label: 'Clinical',   value: c.clinical_score   },
    { label: 'Safety', value: c.safety_score      },
    { label: 'Genetic',    value: c.genetic_score     },
  ].filter((x) => x.value !== null && x.value !== undefined);

  if (!items.length) return null;
  return (
    <div className="flex flex-wrap gap-1.5">
      {items.map(({ label, value }) => (
        <span key={label} className="inline-flex items-center gap-1 text-[11px] px-2 py-0.5 rounded border border-slate-700 bg-slate-900 text-slate-400">
          <span className="text-slate-600">{label}</span>
          <span className="text-slate-300 font-medium">{value}</span>
        </span>
      ))}
    </div>
  );
}

