// ─── Text helpers ─────────────────────────────────────────────────────────────
function firstSentence(value?: string) {
  if (!value) return '';
  return firstSentences(value, 1)[0] || '';
}

function normalizeCommonAbbreviations(value?: string) {
  if (!value) return '';
  return value
    .replace(/\be\s*\.\s*g\s*\./gi, 'e.g.')
    .replace(/\bi\s*\.\s*e\s*\./gi, 'i.e.')
    .replace(/\bet\s*\.\s*c\s*\./gi, 'etc.')
    .replace(/\bv\s*\.\s*s\s*\./gi, 'vs.')
    .replace(/\(\s*e\.g\.\s*,/gi, '(e.g.,')
    .replace(/\(\s*i\.e\.\s*,/gi, '(i.e.,');
}

function shortSnippet(value?: string, maxLength = 220) {
  const sentence = firstSentence(value);
  if (!sentence) return '';
  if (sentence.length <= maxLength) return sentence;
  return `${sentence.slice(0, maxLength).trimEnd()}…`;
}

function firstSentences(value?: string, count = 2) {
  if (!value) return [];
  const normalized = normalizeCommonAbbreviations(value).replace(/\s+/g, ' ').trim();
  const protectedText = normalized
    .replace(/\be\.g\./gi, '__EG__')
    .replace(/\bi\.e\./gi, '__IE__')
    .replace(/\betc\./gi, '__ETC__')
    .replace(/\bvs\./gi, '__VS__');
  const parts =
    protectedText
      .match(/.*?[.!?](?:\s|$)/g)
      ?.map((part) =>
        part
          .replace(/__EG__/g, 'e.g.')
          .replace(/__IE__/g, 'i.e.')
          .replace(/__ETC__/g, 'etc.')
          .replace(/__VS__/g, 'vs.')
          .trim()
      )
      .filter(Boolean)
      .slice(0, count) || [normalized];
  return parts;
}

function splitNarrativeParts(value?: string, maxItems = 6) {
  if (!value) return { lead: '', bullets: [] as string[] };
  const normalized = normalizeCommonAbbreviations(value).replace(/\s+/g, ' ').trim();
  const enumerated = normalized.split(/\(\d+\)\s*/).map((part) => part.trim()).filter(Boolean);
  if (enumerated.length > 1) {
    return {
      lead: enumerated[0].endsWith(':') ? enumerated[0].slice(0, -1) : '',
      bullets: enumerated.slice(1, maxItems + 1).map((item) => item.replace(/[;.]?\s*$/, '').trim()),
    };
  }

  const sentences = firstSentences(normalized, Math.min(maxItems, 4));
  return {
    lead: sentences[0] || '',
    bullets: sentences.slice(1, maxItems).map((item) => item.replace(/[;.]?\s*$/, '').trim()),
  };
}

function NarrativeBlock({
  text,
  className = BODY_TEXT,
}: {
  text?: string;
  className?: string;
}) {
  const { lead, bullets } = splitNarrativeParts(text);
  if (!lead && bullets.length === 0) return null;

  return (
    <div className="space-y-2">
      {lead ? <p className={className}>{lead}</p> : null}
      {bullets.length > 0 ? (
        <ul className="space-y-1.5 pl-4 text-sm leading-relaxed text-slate-300 list-disc marker:text-slate-500">
          {bullets.map((item, index) => (
            <li key={`${item}-${index}`}>{item}</li>
          ))}
        </ul>
      ) : null}
    </div>
  );
}

function summarizeKeyLimitation(report?: any) {
  const geneticText = humanizeGeneticEvidenceText(report?.genetic_evidence_summary).replace(/\s+/g, ' ').trim();
  if (geneticText) {
    const directLimit =
      geneticText.match(/(.*?does not prove.*?[.!?])(?:\s|$)/i)?.[1] ||
      geneticText.match(/(.*?does not establish causality.*?[.!?])(?:\s|$)/i)?.[1];
    if (directLimit) return directLimit.trim();
  }

  const methodologyText = String(report?.methodology || '').replace(/\s+/g, ' ').trim();
  if (methodologyText) {
    const methodologyLimit = methodologyText.match(/Key limitations:\s*(.*?[.!?])(?:\s|$)/i)?.[1];
    if (methodologyLimit) return methodologyLimit.trim();
  }

  return firstSentence(report?.summary);
}

function buildLiteraturePassText(report?: any) {
  const note = String(report?.retrieval_note || '').trim();
  const diagnostics = String(report?.literature_diagnostics?.user_summary || '').trim();
  const carriedCount = Array.isArray(report?.literature_papers) ? report.literature_papers.length : 0;
  const clearedCount = Number(report?.literature_diagnostics?.final_shortlist_count || 0);
  if (carriedCount > 0 && clearedCount > carriedCount) {
    return `${clearedCount} papers cleared disease-specific screening, and ${carriedCount} were carried into the final report payload.`;
  }
  if (note && diagnostics && !note.includes(diagnostics)) {
    return `${note} ${diagnostics}`;
  }
  return note || diagnostics;
}

function humanizePassNote(value?: string) {
  if (!value) return '';
  return value
    .replace(/^1 challenge note were added/i, '1 challenge note was added')
    .replace(/^(\d+) challenge note were added/i, '$1 challenge notes were added')
    .trim();
}

function hasDiseaseContextOnlyEvidence(candidate?: any) {
  const haystack = [
    candidate?.negative_evidence,
    candidate?.score_rationale,
    candidate?.why_candidate,
  ]
    .map((value) => String(value || '').toLowerCase())
    .join(' ');

  return haystack.includes('disease-context evidence') ||
    haystack.includes('none of the supporting papers directly mention this candidate') ||
    haystack.includes('no direct published evidence');
}

function buildTemperedSummaryLead(report?: any, candidate?: any) {
  const fallback = firstSentences(report?.summary, 2).join(' ');
  if (!candidate) return fallback;

  const displayName = getDisplayCandidateName(candidate);
  const lowConfidence = String(candidate?.confidence || '').toLowerCase() === 'low';
  const highFailureRisk = String(candidate?.failure_severity || '').toLowerCase() === 'high';
  const diseaseContextOnly = hasDiseaseContextOnlyEvidence(candidate);

  if (lowConfidence || highFailureRisk || diseaseContextOnly) {
    return `${displayName} emerged as the top signal in this run, but it remains an early-stage hypothesis. The current support is indirect and should be treated as a selective research lead rather than a validated therapeutic candidate.`;
  }

  return fallback;
}

function humanizeMethodologyText(value?: string, report?: any) {
  if (!value) return '';
  const reviewedSignalCount = Array.isArray(report?.reviewed_signal_candidates) ? report.reviewed_signal_candidates.length : 0;
  const topCandidateCount = Array.isArray(report?.top_candidates) ? report.top_candidates.length : 0;
  const earlyStageCount = Array.isArray(report?.early_stage_hypotheses) ? report.early_stage_hypotheses.length : 0;
  if (reviewedSignalCount > 0 && topCandidateCount === 0 && earlyStageCount === 0) {
    const literatureReviewedCount = Number(report?.literature_diagnostics?.retrieved_count || 0);
    const literatureCarriedCount = Array.isArray(report?.literature_papers) ? report.literature_papers.length : 0;
    const candidateReviewedCount =
      Number(String(report?.drugdb_note || '').match(/(\d+) activity-linked molecules/i)?.[1] || 0) ||
      Number(String(report?.drugdb_note || '').match(/(\d+) candidate/i)?.[1] || 0);
    const pathwayCount = Array.isArray(report?.active_trials) ? report.active_trials.length : 0;
    return [
      'Pipeline Overview',
      `This report was generated through a structured research workflow for this condition.`,
      `- The system reviewed ${literatureReviewedCount || 'the available'} papers, carried ${literatureCarriedCount || 'the strongest'} literature records into the report payload, screened ${candidateReviewedCount || 'the available'} candidate contexts, and checked ${pathwayCount || 'the available'} active clinical trial links.`,
      `- The workflow did not produce a scored shortlist, but it retained ${reviewedSignalCount} weak mechanism-linked signals for follow-up review.`,
      '',
      'Evidence Scoring Framework',
      '- A fixed 100-point rubric was configured for literature support, biology overlap, clinical evidence, safety profile, and genetic context.',
      '- In this run, no candidates advanced into formal scoring because no shortlist cleared the stronger candidate threshold.',
      '',
      'Limitations',
      '- These reviewed signals are exploratory only. They were retained because some mechanism-linked evidence existed, but the support was too weak for a reportable candidate or formal early-stage hypothesis.',
      '- Genetic evidence was used as disease-biology context rather than causal proof, and the report does not claim target validation or treatment benefit.',
    ].join('\n');
  }
  const normalized = value.replace(/\s+/g, ' ').trim();
  const diseaseMatch = normalized.match(/for ([^.]+?) candidate prioritization/i);
  if (/structured computational pipeline implemented in node\/typescript/i.test(normalized)) {
    const disease = diseaseMatch?.[1] || 'this condition';
    const literatureCount = normalized.match(/processed (\d+) peer-reviewed publications/i)?.[1];
    const candidateCount = normalized.match(/retrieved (\d+) candidate molecules/i)?.[1];
    const pathwayCount = normalized.match(/contributed (\d+) pathway records/i)?.[1];
    const trialCount = normalized.match(/alongside (\d+) active clinical trial identifiers/i)?.[1];
    const scoredCount = normalized.match(/applied uniformly to (\d+) scored candidates/i)?.[1];
    const noveltySentence =
      normalized.match(/Both .*? These are not .*? development assets\./i)?.[0] ||
      normalized.match(/No candidate cleared the novelty gate.*?\./i)?.[0] ||
      '';
    const subgroupSentence = normalized.match(/This hypothesis achieves greatest plausibility.*?\./i)?.[0] || '';
    const monitoringSentence = normalized.match(/Clinical investigation would necessitate.*?\./i)?.[0] || '';
    const confidenceSentence = normalized.match(/Confidence is assessed as .*?\./i)?.[0] || '';
    const limitationsSentence = normalized.match(/Key constraints: .*?\./i)?.[0] || '';

    return [
      'Pipeline Overview',
      `This report was generated through a structured research workflow for ${disease}.`,
      literatureCount || candidateCount || trialCount || pathwayCount
        ? `- The system reviewed ${literatureCount || 'the available'} published studies, screened ${candidateCount || 'the available'} candidate molecules, checked ${trialCount || 'the available'} active clinical trial links, and incorporated ${pathwayCount || 'the available'} pathway records.`
        : '- The system reviewed published studies, screened candidate molecules, checked active clinical trials, and incorporated pathway context.',
      '- Those findings were then combined with evidence review, adversarial review, risk checks, and final validation before the report was assembled.',
      '',
      'Evidence Scoring Framework',
      scoredCount
        ? `- A fixed 100-point rubric was applied across ${scoredCount} scored candidate${scoredCount === '1' ? '' : 's'}.`
        : '- A fixed 100-point rubric was applied across the scored candidates.',
      '- The scoring considered literature support, biology overlap, clinical evidence, and safety profile.',
      '',
      ...(noveltySentence || subgroupSentence || monitoringSentence || confidenceSentence
        ? [
            'Novelty Search',
            ...(noveltySentence ? [`- ${noveltySentence}`] : []),
            ...(subgroupSentence ? [`- ${subgroupSentence}`] : []),
            ...(monitoringSentence ? [`- ${monitoringSentence}`] : []),
            ...(confidenceSentence ? [`- ${confidenceSentence}`] : []),
            '',
          ]
        : []),
      'Limitations',
      `- ${
        limitationsSentence
          ? limitationsSentence
              .replace(/^Key constraints:\s*/i, '')
              .replace(/genetic support data are included as disease-biology context rather than target validation/i, 'Genetic evidence was used as supporting biology context')
              .replace(/outputs constitute prioritization-grade signals rather than causal proof/i, 'These results should be treated as early research signals')
              .replace(/the report framework explicitly disclaims target validation or efficacy claims/i, 'The report does not claim target validation or treatment benefit')
          : 'These results are early research signals, not proof of cause and effect or treatment benefit.'
      }`,
      '- Provenance records were kept so the data-access trail remains traceable.',
    ].join('\n');
  }
  return value.replace(/Key limitations:\s*$/gi, '').replace(/Key limitations:\s*/gi, '');
}

function humanizeGeneticEvidenceText(value?: string) {
  if (!value) return '';
  const normalized = value.replace(/\s+/g, ' ').trim();
  const genes = normalized.match(/were ([A-Z0-9,\s-]+)\./)?.[1];
  const score = normalized.match(/Genetic support score:\s*([0-9.]+)/i)?.[1];
  if (genes) {
    return `We reviewed disease-biology signals linked to this condition. The strongest genes in this pass were ${genes}. This makes candidates connected to these pathways more relevant for follow-up, but it does not prove that any one gene or drug is the cause.${score ? ` Genetic support score: ${score}. On a 0 to 1 scale, higher means a stronger disease-gene signal in this run.` : ''}`;
  }
  return normalized
    .replace(/Genetic support score:\s*([0-9.]+)/gi, 'Genetic support score: $1. On a 0 to 1 scale, higher means a stronger disease-gene signal in this run')
    .replace(/We reviewed supportive disease-biology evidence from OpenTargets associatedTargets proxy\.?/gi, 'We reviewed disease-biology signals linked to this condition.')
    .replace(/OpenTargets associatedTargets proxy/gi, 'disease-biology sources')
    .replace(/supportive disease-biology evidence/gi, 'disease-biology signals')
    .replace(/genetic support data/gi, 'genetic evidence');
}

function humanizeNoveltySearchText(value?: string) {
  if (!value) return '';
  const normalized = value.replace(/\s+/g, ' ').trim();
  if (/IMETELSTAT/i.test(normalized) && /\bIPF\b/i.test(normalized)) {
    return 'IMETELSTAT stands out as a possible repurposing idea for IPF because its biology overlaps with telomere-related disease signals. This is still an early research signal, not a proven IPF treatment, and any follow-up would require careful patient selection and biomarker monitoring.';
  }
  return normalized
    .replace(/OpenTargets associatedTargets proxy/gi, 'disease-biology sources')
    .replace(/\bcross-indication repurposing\b/gi, 'repurposing from another disease area')
    .replace(/\bcross-indication\b/gi, 'from another disease area')
    .replace(/\bdisease-native assets?\b/gi, 'existing candidates in this disease area')
    .replace(/\bbona fide\b/gi, 'genuine')
    .replace(/\bformulations\b/gi, 'versions')
    .replace(/\bCHEMBL\d+\b/gi, 'an investigational candidate');
}

function humanizeCommonFailureText(value?: string) {
  if (!value) return '';
  return value
    .replace(/\bcftr-axis\b/gi, 'CFTR-axis')
    .replace(/\btelomere-maintenance\b/gi, 'telomere-maintenance')
    .replace(/\bdna-repair\b/gi, 'DNA-repair')
    .replace(/\bwnt-beta-catenin\b/gi, 'Wnt/beta-catenin')
    .replace(/\bfibrosis-remodeling\b/gi, 'fibrosis-remodeling')
    .replace(/\bepithelial-trafficking\b/gi, 'epithelial trafficking')
    .replace(/\bCHEMBL\d+\b/gi, 'an investigational candidate')
    .trim();
}

function humanizeCandidateText(value?: string) {
  if (!value) return '';
  return normalizeCommonAbbreviations(value)
    .replace(/\s+/g, ' ')
    .replace(/OpenTargets associatedTargets proxy/gi, 'disease-biology sources')
    .replace(/\bcross-indication repurposing\b/gi, 'repurposing from another disease area')
    .replace(/\bcross-indication\b/gi, 'from another disease area')
    .replace(/\bdisease-native assets?\b/gi, 'existing candidates in this disease area')
    .replace(/\bIPF-native assets?\b/gi, 'existing IPF candidates')
    .replace(/\bbona fide\b/gi, 'genuine')
    .replace(/\bhematologic\b/gi, 'blood-related')
    .replace(/\bfibroproliferative\b/gi, 'fibrosis-related')
    .replace(/\bformulations\b/gi, 'versions')
    .replace(/\bCHEMBL\d+\b/gi, 'this investigational candidate')
    .trim();
}

function isOpaqueCandidateId(value?: string) {
  return /^CHEMBL\d+$/i.test(String(value || '').trim());
}

function inferCandidateAnchorText(candidate: any) {
  const haystack = [
    candidate?.mechanism_hypothesis,
    candidate?.why_candidate,
    candidate?.mechanism_overlap,
    candidate?.novelty_basis,
    candidate?.summary,
  ]
    .map((value) => String(value || ''))
    .join(' ');

  const patterns: Array<[RegExp, string]> = [
    [/\bNorrin\b|\bWnt\b/i, 'Norrin/Wnt'],
    [/\bCereblon\b.*\bDJ-1\b|\bDJ-1\b.*\bCereblon\b/i, 'Cereblon-DJ-1 degrader'],
    [/\bgamma-secretase\b|\bNicastrin\b/i, 'gamma-secretase'],
    [/\bRET\b|\bGDNF\b/i, 'RET/GDNF'],
    [/\bPolycystin-1\b|\bPKD1\b/i, 'Polycystin-1'],
    [/\bDJ-1\b|\bPARK7\b/i, 'DJ-1'],
    [/\bSNCA\b|\balpha-synuclein\b/i, 'SNCA-linked'],
    [/\bLRRK2\b/i, 'LRRK2-linked'],
    [/\bATP13A2\b/i, 'ATP13A2-linked'],
    [/\bPINK1\b|\bPRKN\b/i, 'mitophagy-linked'],
  ];

  for (const [pattern, label] of patterns) {
    if (pattern.test(haystack)) return label;
  }
  return '';
}

function getDisplayCandidateName(candidate: any) {
  const explicitDisplayName = String(candidate?.display_name || '').trim();
  if (explicitDisplayName) return explicitDisplayName;
  const rawName = String(candidate?.drug_name || '').trim();
  if (!isOpaqueCandidateId(rawName)) return rawName;

  const anchor = inferCandidateAnchorText(candidate);
  if (!anchor) return 'Investigational candidate';

  const role = String(candidate?.candidate_role || '').toLowerCase();
  if (role.includes('degrader')) return `${anchor} candidate`;
  if (role.includes('mechanism-first')) return `${anchor} candidate`;
  if (role.includes('repurposing')) return `${anchor} repurposing candidate`;
  return `${anchor} candidate`;
}

function getValidationCheckLabel(candidate: any) {
  const displayName = getDisplayCandidateName(candidate);
  const rawName = String(candidate?.drug_name || '').trim();
  if (displayName === 'Investigational candidate' && isOpaqueCandidateId(rawName)) {
    return rawName;
  }
  return displayName;
}

function humanizeDiscoveryFit(value?: string) {
  if (!value) return '';
  return value
    .replace(/^Early-stage repurposing fit$/i, 'Early research fit')
    .replace(/^Clinical-stage repurposing fit$/i, 'Clinical-stage fit')
    .replace(/^Cross-indication repurposing fit$/i, 'Repurposing fit')
    .replace(/^Known disease asset$/i, 'Known in-disease asset');
}

function humanizeGeneticTier(value?: string) {
  if (value === 'Tier 1') return 'genetic + mechanistic';
  if (value === 'Tier 2') return 'mechanistic with genetic context';
  if (value === 'Tier 3') return 'speculative';
  return value || '';
}

function humanizeDriverStrength(value?: string) {
  if (value === 'strong') return 'strong';
  if (value === 'moderate') return 'medium';
  if (value === 'limited') return 'limited';
  if (value === 'weak') return 'weak';
  if (value === 'high') return 'high';
  if (value === 'low') return 'low';
  return value || '';
}

function humanizeEvidenceBasis(value?: string) {
  if (value === 'direct') return 'direct basis';
  if (value === 'indirect') return 'indirect basis';
  if (value === 'speculative') return 'speculative basis';
  return value || '';
}

function humanizePaymentAgent(value?: string) {
  if (value === 'literature') return 'Literature service';
  if (value === 'drugdb') return 'DrugDB service';
  if (value === 'pathway') return 'Pathway service';
  if (value === 'red_team') return 'Independent red-team review';
  if (value === 'pi') return 'Peer-review evaluator';
  return value ? `${value.replace(/_/g, ' ')} agent` : 'Agent payment';
}

function humanizePaymentPurpose(value?: string) {
  if (value === 'literature-search') return 'PI paid for literature retrieval, filtering, and synthesis';
  if (value === 'drugdb-fetch') return 'PI paid for target and candidate screening';
  if (value === 'pathway-analysis') return 'PI paid for pathway and disease-biology interpretation';
  if (value === 'red-team-review') return 'PI paid for an independent red-team review';
  if (value === 'evaluator-review') return 'Paid for peer review';
  return 'Paid for a research service';
}

function isExplorerTxHash(value?: string) {
  return /^0x[a-fA-F0-9]{64}$/.test(value || '');
}

function humanizePaymentNetwork(value?: string) {
  if (!value) return '';
  if (value.toLowerCase() === 'arc-testnet') return 'Arc Testnet';
  return value;
}

function humanizePaymentMode(value?: string) {
  if (!value) return '';
  if (value === 'circle-gateway') return 'Gasless authorization with Gateway batched settlement';
  return value;
}

function findRelatedTrials(drugName: string, trials: any[]) {
  const needle = drugName.toLowerCase();
  return trials.filter((trial) =>
    Array.isArray(trial.drugs) &&
    trial.drugs.some((drug: string) => {
      const normalized = String(drug || '').toLowerCase();
      return normalized.includes(needle) || needle.includes(normalized);
    })
  );
}

// ─── Chevron icon ─────────────────────────────────────────────────────────────
// ─── Methodology renderer ─────────────────────────────────────────────────────
// Handles two cases:
//   1. Structured text (has newlines/bullets) → line-by-line parse
//   2. Single dense paragraph → sentence-split + topic grouping

const METHODOLOGY_SECTIONS = [
  {
    heading: 'Pipeline Overview',
    pattern: /literature agent|drug database|pathway agent|repurposing agent|multi-agent|screened|candidate compound|shortlist/i,
  },
  {
    heading: 'Evidence Scoring Framework',
    pattern: /evidence scor|rubric|ranked.*candidate|literature support|mechanism overlap|clinical evidence|safety profile|100-point|\(0[-–]/i,
  },
  {
    heading: 'Limitations',
    pattern: /not available|genetic support|GWAS|eQTL|Mendelian|causal interpretation|limited without/i,
  },
  {
    heading: 'Reporting Layer',
    pattern: /report layer|re-score|converted.*score|highlighted negative|marked.*asset|user-facing/i,
  },
  {
    heading: 'Interpretation Note',
    pattern: /final writeup|prioritization layer|not a.*conclusion|assumptions.*evidence gap|evidence gap.*assumption/i,
  },
];

type MdToken =
  | { type: 'heading'; text: string }
  | { type: 'para';    text: string }
  | { type: 'bullet';  text: string; depth: number };

function rewritePipelineOverview(sentences: string[]) {
  const joined = sentences.join(' ');
  const diseaseMatch = joined.match(/pipeline for ([^.]+)\./i);
  const literatureMatch = joined.match(/screened (\d+) papers/i);
  const candidateMatch = joined.match(/returned (\d+) candidate compounds/i);
  const pathwayMatch = joined.match(/contributed (\d+) pathway records and (\d+) clinical trial links/i);
  const shortlistMatch = joined.match(/generated (\d+) shortlist hypotheses/i);

  const disease = diseaseMatch?.[1] || 'this disease';
  const literatureCount = literatureMatch?.[1];
  const candidateCount = candidateMatch?.[1];
  const pathwayCount = pathwayMatch?.[1];
  const trialCount = pathwayMatch?.[2];
  const shortlistCount = shortlistMatch?.[1];

  if (!literatureCount || !candidateCount || !pathwayCount || !trialCount || !shortlistCount) {
    return sentences;
  }

  return [
    `This report was generated through a structured research workflow for ${disease}.`,
    `The system reviewed ${literatureCount} published studies, screened ${candidateCount} candidate molecules, and checked ${trialCount} active clinical trial links.`,
    `Those findings were then combined with pathway review, candidate ranking, risk checks, and final validation before the shortlist of ${shortlistCount} hypotheses was assembled.`,
  ];
}

function rewriteReportingLayer(sentences: string[]) {
  const joined = sentences.join(' ');
  if (!/report layer|re-score|highlighted negative|known disease assets|repurposing opportunities/i.test(joined)) {
    return sentences;
  }

  return [
    'The report layer did not change the scores. Instead, it:',
    'Turned technical scores and risks into clear explanations',
    'Highlighted negative evidence',
    'Flagged cases that may already be known disease treatments rather than true repurposing opportunities',
  ];
}

function parseMethodology(raw: string): MdToken[] {
  const cleanedRaw = raw
    .replace(
      /Each candidate also includes three qualitative labels: Evidence estimates how strong the disease-specific support is in this run, Maturity indicates how clinically established or development-ready the candidate already is, and Risk reflects how difficult, uncertain, or safety-constrained it may be to advance\.\s*/g,
      '',
    )
    .replace(
      /In practice, low Evidence usually means sparse, indirect, early-stage, or inconsistent support; high Maturity usually means the drug is already well known, clinically studied, or approved elsewhere; and low Risk usually means the safety and operational profile is relatively better understood\.\s*/g,
      '',
    )
    .trim();

  const isStructured = cleanedRaw.includes('\n');

  // ── Structured path ────────────────────────────────────────────────────────
  if (isStructured) {
    const tokens: MdToken[] = [];
    let prevBlank = true;
    for (const line of cleanedRaw.split('\n')) {
      if (line.trim() === '') { prevBlank = true; continue; }
      const sub = line.match(/^(\s{2,})[-•*]\s+(.+)/);
      if (sub) { tokens.push({ type: 'bullet', text: sub[2].trim(), depth: 1 }); prevBlank = false; continue; }
      const bul = line.match(/^[-•*]\s+(.+)/);
      if (bul) { tokens.push({ type: 'bullet', text: bul[1].trim(), depth: 0 }); prevBlank = false; continue; }
      if (prevBlank && line.trim().length <= 60 && !/[,;]/.test(line)) {
        tokens.push({ type: 'heading', text: line.trim() }); prevBlank = false; continue;
      }
      tokens.push({ type: 'para', text: line.trim() });
      prevBlank = false;
    }
    return tokens;
  }

  // ── Flat paragraph path: split by ". " then group by topic ────────────────
  const sentences = cleanedRaw
    .replace(/([.!?])\s+/g, '$1\n')
    .split('\n')
    .map(s => s.trim())
    .filter(Boolean);

  // Bucket sentences into sections
  type Bucket = { heading: string; sentences: string[] };
  const intro: string[] = [];
  const buckets: Bucket[] = METHODOLOGY_SECTIONS.map(s => ({ heading: s.heading, sentences: [] }));
  const overflow: string[] = [];

  for (const sentence of sentences) {
    const idx = METHODOLOGY_SECTIONS.findIndex(s => s.pattern.test(sentence));
    if (idx !== -1) {
      buckets[idx].sentences.push(sentence);
    } else if (buckets.every(b => b.sentences.length === 0)) {
      intro.push(sentence);
    } else {
      // Attach to the last bucket that has content
      const last = [...buckets].reverse().find(b => b.sentences.length > 0);
      if (last) last.sentences.push(sentence); else overflow.push(sentence);
    }
  }

  const tokens: MdToken[] = [];
  if (intro.length) tokens.push({ type: 'para', text: intro.join(' ') });

  for (const bucket of buckets) {
    if (!bucket.sentences.length) continue;
    if (bucket.heading === 'Interpretation Note') continue;
    tokens.push({ type: 'heading', text: bucket.heading });
    const renderedSentences =
      bucket.heading === 'Pipeline Overview'
        ? rewritePipelineOverview(bucket.sentences)
        : bucket.heading === 'Reporting Layer'
          ? rewriteReportingLayer(bucket.sentences)
        : bucket.sentences;
    for (const [index, s] of renderedSentences.entries()) {
      const tokenType = bucket.heading === 'Reporting Layer' && index === 0 ? 'para' : 'bullet';
      tokens.push({ type: tokenType, text: s, depth: 0 });
    }
  }
  if (overflow.length) tokens.push({ type: 'para', text: overflow.join(' ') });

  return tokens;
}

function renderInline(text: string) {
  const parts = text.split(/(\*\*[^*]+\*\*)/g);
  return parts.map((part, i) =>
    part.startsWith('**') && part.endsWith('**')
      ? <strong key={i} className="font-semibold text-slate-200">{part.slice(2, -2)}</strong>
      : <span key={i}>{part}</span>
  );
}

function MethodologyRenderer({ text }: { text: string }) {
  const tokens = parseMethodology(text);
  const signalLabelBlock = (
    <div className="mt-3 mb-1 rounded-xl border border-slate-800/80 bg-slate-900/55 px-4 py-4">
      <p className="text-sm font-semibold text-slate-100">Key Evaluation Dimensions</p>
      <p className="mt-2 text-sm leading-relaxed text-slate-300">
        Each candidate was evaluated across three core dimensions:
      </p>
      <ul className="mt-3 space-y-3 pl-4 text-sm text-slate-300 list-disc marker:text-slate-500">
        <li>
          <p className="leading-relaxed"><strong className="text-sm font-semibold text-slate-100">Evidence</strong></p>
          <p className="leading-relaxed">Reflects how strong the disease-specific support is.</p>
          <p className="leading-relaxed italic text-slate-300/90">
            -&gt; Low evidence typically means the data is limited, indirect, early-stage, or inconsistent.
          </p>
        </li>
        <li>
          <p className="leading-relaxed"><strong className="text-sm font-semibold text-slate-100">Maturity</strong></p>
          <p className="leading-relaxed">Indicates how clinically established the candidate is.</p>
          <p className="leading-relaxed italic text-slate-300/90">
            -&gt; High maturity suggests the drug is already well studied, clinically tested, or approved for another use.
          </p>
        </li>
        <li>
          <p className="leading-relaxed"><strong className="text-sm font-semibold text-slate-100">Risk</strong></p>
          <p className="leading-relaxed">Captures uncertainty, development difficulty, and safety concerns.</p>
          <p className="leading-relaxed italic text-slate-300/90">
            -&gt; Low risk generally means the safety profile and operational feasibility are better understood.
          </p>
        </li>
      </ul>
    </div>
  );

  return (
    <div className="space-y-2.5">
      {tokens.map((token, i) => {
        if (token.type === 'heading') {
          return (
            <>
              <p className="text-[10px] font-semibold uppercase tracking-[0.18em] text-sky-400/70 pt-3 first:pt-0">
                {token.text}
              </p>
              {token.text === 'Evidence Scoring Framework' ? signalLabelBlock : null}
            </>
          );
        }
        if (token.type === 'bullet') {
          return (
            <div key={i} className="flex items-start gap-2" style={{ paddingLeft: token.depth * 16 }}>
              <span className="mt-[7px] w-1 h-1 rounded-full bg-slate-600 flex-shrink-0" aria-hidden="true" />
              <p className="text-sm leading-relaxed text-slate-300">{renderInline(token.text)}</p>
            </div>
          );
        }
        return (
          <p key={i} className="text-sm leading-relaxed text-slate-300">{renderInline(token.text)}</p>
        );
      })}
    </div>
  );
}

function ChevronIcon({ open }: { open: boolean }) {
  return (
    <svg
      className={`w-4 h-4 text-slate-500 transition-transform duration-200 ${open ? 'rotate-180' : ''}`}
      fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24" aria-hidden="true"
    >
      <path strokeLinecap="round" strokeLinejoin="round" d="m19 9-7 7-7-7" />
    </svg>
  );
}

// ─── Candidate card ───────────────────────────────────────────────────────────
function CandidateCard({
  c,
  relatedTrials = [],
  isExpanded,
  onToggle,
  variant = 'full',
}: {
  c: any;
  relatedTrials?: any[];
  isExpanded: boolean;
  onToggle: () => void;
  variant?: 'full' | 'doctor';
}) {
  const whyItMatters = humanizeCandidateText(c.why_candidate || c.mechanism_hypothesis || c.mechanism_overlap);
  const whyNot       = firstSentences(humanizeCandidateText(c.false_positive_risk || c.negative_evidence || c.main_risk || 'No major counter-signal captured in this run.'), 2).join(' ');
  const howToTest    = humanizeCandidateText(c.testable_prediction || c.biomarker_link || 'No concrete next step was generated in this run.');
  const noveltyBasis = humanizeCandidateText(c.novelty_basis || '');
  const hasScore     = c.total_score !== null && c.total_score !== undefined;
  const doctorMode = variant === 'doctor';
  const visibleScore = c.adjusted_score ?? c.total_score;
  const failureMode = firstSentence(humanizeCandidateText(c.failure_mode || whyNot));
  const disconfirmingSignal = firstSentence(humanizeCandidateText(c.disconfirming_signal || ''));
  const criticalTest = firstSentence(humanizeCandidateText(c.critical_test || howToTest));
  const confidenceDrivers = c.confidence_drivers;
  const displayName = getDisplayCandidateName(c);
  const showTechnicalId = isOpaqueCandidateId(c.drug_name) && c.molecule_chembl_id;
  const diseaseContextOnlyEvidence = hasDiseaseContextOnlyEvidence(c);

  return (
    <div className={INNER_CARD}>
      {/* ── Always-visible header ── */}
      <div className="flex items-start gap-4">
        {hasScore && !doctorMode && <ScoreRing score={visibleScore} />}
        <div className="flex-1 min-w-0">
          {/* Row 1: name */}
          <h3 className="text-sm font-semibold tracking-tight text-white">{displayName}</h3>
          {showTechnicalId && (
            <p className={`${MUTED_TEXT} mt-0.5`}>ChEMBL ID: {c.molecule_chembl_id}</p>
          )}
          {/* Row 2: current use */}
          {c.current_use && (
            <p className={`${MUTED_TEXT} mt-0.5`}>Used today for: {humanizeCandidateText(c.current_use)}</p>
          )}
          {/* Row 3: badges */}
          <div className="flex flex-wrap gap-1.5 mt-2">
            {c.novelty_class === 'novel' && (
              <span className="text-[11px] px-2.5 py-0.5 rounded-full border border-violet-700 bg-violet-950/40 text-violet-300 font-medium">
                new idea
              </span>
            )}
            {c.discovery_fit && (
              <span className="text-[11px] px-2.5 py-0.5 rounded-full border border-slate-700 bg-slate-900/70 text-slate-300 font-medium">
                {humanizeDiscoveryFit(c.discovery_fit)}
              </span>
            )}
            <span className={`text-[11px] px-2.5 py-0.5 rounded-full border font-medium ${confidenceBadge(c.confidence)}`}>
              {c.confidence} confidence
            </span>
            {diseaseContextOnlyEvidence && !doctorMode && (
              <span className="text-[11px] px-2.5 py-0.5 rounded-full border border-amber-700/70 bg-amber-950/30 text-amber-200 font-medium">
                disease-context evidence only
              </span>
            )}
            {c.genetic_confidence_tier && (
              <span className="text-[11px] px-2.5 py-0.5 rounded-full border border-sky-800/70 bg-sky-950/30 text-sky-300 font-medium">
                {humanizeGeneticTier(c.genetic_confidence_tier)}
              </span>
            )}
            {!doctorMode && c.failure_severity && (
              <span className={`text-[11px] px-2.5 py-0.5 rounded-full border font-medium ${levelBadge(c.failure_severity)}`}>
                {c.failure_severity} failure risk
              </span>
            )}
          </div>
          {/* Row 4: sub-scores */}
          {hasScore && !doctorMode && <div className="mt-2"><SubScorePills c={c} /></div>}
          {!doctorMode && confidenceDrivers && (
            <div className="mt-3 rounded-lg border border-slate-800/80 bg-slate-950/50 px-3 py-3">
              <p className={`${SECTION_LABEL} mb-2`}>Confidence Drivers</p>
              <div className="grid gap-1.5 text-xs text-slate-300 sm:grid-cols-2">
                <p><span className="text-slate-500">Evidence strength:</span> {humanizeDriverStrength(confidenceDrivers.evidence_strength)}</p>
                <p><span className="text-slate-500">Genetic support:</span> {humanizeDriverStrength(confidenceDrivers.genetic_support)}</p>
                <p><span className="text-slate-500">Red-team severity:</span> {humanizeDriverStrength(confidenceDrivers.red_team_severity)}</p>
                <p><span className="text-slate-500">Clinical maturity:</span> {humanizeDriverStrength(confidenceDrivers.clinical_maturity)}</p>
              </div>
              {confidenceDrivers.summary && (
                <p className="mt-2 text-xs leading-relaxed text-slate-400">{humanizeCandidateText(confidenceDrivers.summary)}</p>
              )}
            </div>
          )}
          {!doctorMode && c.evidence_trace && (
            <p className={`${MUTED_TEXT} mt-2`}>
              Evidence trace: {humanizeCandidateText(c.evidence_trace)}
            </p>
          )}
          {c.causal_support && !doctorMode && (
            <p className={`${MUTED_TEXT} mt-2`}>Biology link: {humanizeCandidateText(c.causal_support)}</p>
          )}
          {!doctorMode && c.genetic_signal_provenance && (
            <p className={`${MUTED_TEXT} mt-1.5`}>
              Genetic context: {humanizeCandidateText(c.genetic_signal_provenance)}
            </p>
          )}
          {doctorMode && relatedTrials.length > 0 && (
            <p className={`${MUTED_TEXT} mt-2`}>
              Active clinical touchpoints in this run: {relatedTrials.slice(0, 2).map((trial) => trial.nct_id).join(', ')}
            </p>
          )}
        </div>
      </div>

      {/* ── Expanded content ── */}
      {isExpanded && (
        <>
          {/* Known disease asset warning */}
          {c.known_disease_asset === true && (
            <div className="mt-4 flex items-start gap-2 rounded-lg border border-amber-800/50 bg-amber-950/20 px-3 py-2.5">
              <svg className="w-4 h-4 text-amber-400 flex-shrink-0 mt-0.5" fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24" aria-hidden="true">
                <path strokeLinecap="round" strokeLinejoin="round" d="M12 9v3.75m-9.303 3.376c-.866 1.5.217 3.374 1.948 3.374h14.71c1.73 0 2.813-1.874 1.948-3.374L13.949 3.378c-.866-1.5-3.032-1.5-3.898 0L2.697 16.126ZM12 15.75h.007v.008H12v-.008Z" />
              </svg>
              <p className="text-xs text-amber-300/90 leading-relaxed">
                Known disease asset — this looks like an existing disease-program candidate rather than a clean repurposing case.
              </p>
            </div>
          )}

          {/* Content sections */}
          <div className="mt-5 grid gap-4">
            <div className="border-l-2 border-sky-800/60 pl-3">
              <p className={`${SECTION_LABEL} mb-1`}>{doctorMode ? 'What This Suggests' : 'Why It Stands Out'}</p>
              <NarrativeBlock text={whyItMatters} />
              {noveltyBasis && !doctorMode && (
                <p className={`${BODY_TEXT} mt-1.5 text-violet-300/90`}>{noveltyBasis}</p>
              )}
            </div>
            {!doctorMode && (
              <div className="border-l-2 border-rose-900/60 pl-3">
                <p className={`${SECTION_LABEL} mb-1`}>Main Caution</p>
                <NarrativeBlock text={whyNot} />
              </div>
            )}
            {!doctorMode && (
              <div className="border-l-2 border-orange-900/60 pl-3">
                <p className={`${SECTION_LABEL} mb-1`}>Failure Mode</p>
                <NarrativeBlock text={failureMode} />
                {(c.failure_evidence_basis || c.failure_severity) && (
                  <p className={`${BODY_TEXT} mt-1.5 text-slate-400`}>
                    {c.failure_severity ? `${c.failure_severity} failure risk` : ''}
                    {c.failure_severity && c.failure_evidence_basis ? ' · ' : ''}
                    {c.failure_evidence_basis ? humanizeEvidenceBasis(c.failure_evidence_basis) : ''}
                  </p>
                )}
              </div>
            )}
            <div className="border-l-2 border-emerald-900/60 pl-3">
              <p className={`${SECTION_LABEL} mb-1`}>{doctorMode ? 'Who Might Benefit' : 'What To Check Next'}</p>
              <NarrativeBlock text={doctorMode ? humanizeCandidateText(c.subgroup_link || c.biomarker_link || howToTest) : criticalTest} />
              {c.biomarker_link && !doctorMode && (
                <p className={`${BODY_TEXT} mt-1.5`}>
                  <span className="text-slate-500">Biomarker: </span>{humanizeCandidateText(c.biomarker_link)}
                </p>
              )}
              {c.subgroup_link && !doctorMode && (
                <p className={`${BODY_TEXT} mt-1`}>
                  <span className="text-slate-500">Best-fit group: </span>{humanizeCandidateText(c.subgroup_link)}
                </p>
              )}
              {disconfirmingSignal && !doctorMode && (
                <div className="mt-1.5">
                  <p className={`${BODY_TEXT} text-slate-500 mb-1`}>What would weaken this</p>
                  <NarrativeBlock text={disconfirmingSignal} />
                </div>
              )}
            </div>
            {doctorMode && relatedTrials.length > 0 && (
              <div className="border-l-2 border-amber-900/60 pl-3">
                <p className={`${SECTION_LABEL} mb-1`}>Active Trials In This Run</p>
                <div className="space-y-2">
                  {relatedTrials.slice(0, 3).map((trial) => (
                    <div key={trial.nct_id} className="rounded-lg border border-slate-800 bg-slate-950/40 px-3 py-2">
                      <p className="text-sm text-slate-200">{trial.title}</p>
                      <div className="mt-1 flex flex-wrap gap-2 text-[11px] text-slate-400">
                        <span>{trial.nct_id}</span>
                        {trial.phase ? <span>{trial.phase}</span> : null}
                        {trial.status ? <span>{trial.status}</span> : null}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>

          {/* PMIDs */}
          {c.supporting_pmids?.length > 0 && !doctorMode && (
            <div className="mt-4 pt-4 border-t border-slate-800/80">
              <div className="mb-2 flex flex-wrap items-center gap-2">
                <p className={SECTION_LABEL}>Supporting PMIDs</p>
                {diseaseContextOnlyEvidence && (
                  <span className="text-[11px] px-2 py-0.5 rounded-full border border-amber-700/70 bg-amber-950/30 text-amber-200 font-medium">
                    No direct candidate-specific paper found
                  </span>
                )}
              </div>
              <div className="flex flex-wrap gap-1.5">
                {c.supporting_pmids.map((pmid: string) => (
                  <a
                    key={pmid}
                    href={`https://pubmed.ncbi.nlm.nih.gov/${pmid}`}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="text-[11px] px-2 py-0.5 rounded border border-sky-900/60 bg-sky-950/30 text-sky-400 hover:text-sky-300 hover:border-sky-700 transition-colors duration-150 font-mono"
                  >
                    {pmid}
                  </a>
                ))}
              </div>
            </div>
          )}
        </>
      )}

      {/* ── Expand toggle ── */}
      <button
        type="button"
        onClick={onToggle}
        className="mt-4 flex items-center gap-1.5 text-xs font-medium text-slate-400 hover:text-sky-300 transition-colors duration-150 cursor-pointer focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-sky-500 rounded"
        aria-expanded={isExpanded}
      >
        <ChevronIcon open={isExpanded} />
        {isExpanded ? 'Collapse details' : 'Expand details'}
      </button>
    </div>
  );
}

function ReviewedSignalCard({ c }: { c: any }) {
  const displayName = getDisplayCandidateName(c);
  const whyReviewed = humanizeCandidateText(c.why_candidate || c.mechanism_hypothesis || c.mechanism_overlap);
  const whyHeldBack = humanizeCandidateText(
    c.false_positive_risk ||
    c.failure_mode ||
    c.negative_evidence ||
    c.main_risk ||
    'This signal did not clear the current shortlist threshold.'
  );
  const nextCheck = humanizeCandidateText(c.critical_test || c.testable_prediction || c.biomarker_link || '');
  const visibleScore = c.adjusted_score ?? c.total_score;
  const showTechnicalId = isOpaqueCandidateId(c.drug_name) && c.molecule_chembl_id;

  return (
    <div className={INNER_CARD}>
      <div className="flex items-start gap-4">
        {typeof visibleScore === 'number' ? <ScoreRing score={visibleScore} /> : null}
        <div className="min-w-0 flex-1">
          <h3 className="text-sm font-semibold tracking-tight text-white">{displayName}</h3>
          {showTechnicalId ? <p className={`${MUTED_TEXT} mt-0.5`}>ChEMBL ID: {c.molecule_chembl_id}</p> : null}
          <div className="mt-2 flex flex-wrap gap-1.5">
            {c.discovery_fit ? (
              <span className="text-[11px] px-2.5 py-0.5 rounded-full border border-slate-700 bg-slate-900/70 text-slate-300 font-medium">
                {humanizeDiscoveryFit(c.discovery_fit)}
              </span>
            ) : null}
            {c.confidence ? (
              <span className={`text-[11px] px-2.5 py-0.5 rounded-full border font-medium ${confidenceBadge(c.confidence)}`}>
                {c.confidence} confidence
              </span>
            ) : null}
            <span className="text-[11px] px-2.5 py-0.5 rounded-full border border-slate-700 bg-slate-900/70 text-slate-300 font-medium">
              reviewed signal
            </span>
          </div>
          {c.evidence_trace ? (
            <p className={`${MUTED_TEXT} mt-2`}>
              Evidence trace: {humanizeCandidateText(c.evidence_trace)}
            </p>
          ) : null}
        </div>
      </div>
      <div className="mt-5 grid gap-4">
        <div className="border-l-2 border-sky-800/60 pl-3">
          <p className={`${SECTION_LABEL} mb-1`}>Why It Was Reviewed</p>
          <NarrativeBlock text={whyReviewed} />
        </div>
        <div className="border-l-2 border-rose-900/60 pl-3">
          <p className={`${SECTION_LABEL} mb-1`}>Why It Did Not Advance</p>
          <NarrativeBlock text={whyHeldBack} />
        </div>
        {nextCheck ? (
          <div className="border-l-2 border-emerald-900/60 pl-3">
            <p className={`${SECTION_LABEL} mb-1`}>Useful Next Check</p>
            <NarrativeBlock text={nextCheck} />
          </div>
        ) : null}
      </div>
    </div>
  );
}


